INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (0, 24001, 102601, "リン", 10040, "あたしだって\nやるときはやるよ！", 0.0, 1, 24, 0.0, 0.0, 1, "2030/12/17 14:59:59", "2020/04/30 12:00:00");
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (1, 24002, 102601, "リン", 10040, "ふぅ…\nこれであたしの仕事は\n終わりだね", 0.0, 1, 24, 0.0, 0.0, 1, "2030/12/17 14:59:59", "2020/04/30 12:00:00");
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (2, 24003, 102601, "リン", 10040, "終わった終わった\n一人でもなんとか\nなるもんだね", 0.0, 1, 24, 0.0, 0.0, 1, "2030/12/17 14:59:59", "2020/04/30 12:00:00");
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (3, 24004, 102601, "リン", 10040, "やったね！\nこれでようやく\nサボれるよ…", 0.0, 2, 24, 0.0, 0.0, 2, "2030/12/17 14:59:59", "2020/04/30 12:00:00");
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (4, 24005, 102601, "リン", 10040, "チーズが欲しいなら\nきちんと働いて\n買いに来なよ", 0.0, 1, 24, 0.0, 0.0, 1, "2030/12/17 14:59:59", "2020/04/30 12:00:00");
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (5, 24006, 102601, "リン", 10040, "あたしを敵に回した\n恐ろしさ\n思い知ったか！", 0.0, 2, 24, 0.0, 0.0, 2, "2030/12/17 14:59:59", "2020/04/30 12:00:00");
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (6, 24007, 102601, "リン", 10040, "あたしも意外と\nやるもんでしょ？", 0.0, 2, 24, 0.0, 0.0, 2, "2030/12/17 14:59:59", "2020/04/30 12:00:00");
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (7, 24008, 102601, "リン", 10040, "疲れた…\nねずみの逃げ足\n速すぎるよ…", 0.0, 4, 24, 0.0, 0.0, 4, "2030/12/17 14:59:59", "2020/04/30 12:00:00");
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (8, 24009, 102601, "リン", 10040, "このままじゃ\nまっひ～に\n叱られちゃうよ", 0.0, 4, 24, 0.0, 0.0, 4, "2030/12/17 14:59:59", "2020/04/30 12:00:00");
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (9, 24010, 102601, "リン", 10040, "まじめに\nやったんだけどな…\n悔しいな～", 0.0, 4, 24, 0.0, 0.0, 4, "2030/12/17 14:59:59", "2020/04/30 12:00:00");
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (10, 24011, 102601, "リン", 10040, "やられた…\nねずみって意外と\nてごわいね", 0.0, 4, 24, 0.0, 0.0, 4, "2030/12/17 14:59:59", "2020/04/30 12:00:00");
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (11, 24012, 102601, "リン", 10040, "おのれ～\nあたしのチーズを\n盗みやがって～！", 0.0, 4, 24, 0.0, 0.0, 4, "2030/12/17 14:59:59", "2020/04/30 12:00:00");
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (12, 24013, 102601, "リン", 10040, "疲れた…\nけど、次こそは\n守り抜くよ…", 0.0, 4, 24, 0.0, 1.81, 1, "2030/12/17 14:59:59", "2020/04/30 12:00:00");
